-- 4. EXERCISE SUBSTITUTIONS
-- ════════════════════════════════════════════════════════════════════════════

INSERT IGNORE INTO exercise_substitutions (exercise_id, substitute_exercise_id, reason, equivalence_level)
SELECT p.id, s.id, 'Equipment alternative', 'SIMILAR'
FROM exercises p JOIN exercises s ON s.id != p.id
WHERE (p.slug = 'bench-press'   AND s.slug = 'dumbbell-bench-press')
   OR (p.slug = 'bench-press'   AND s.slug = 'push-up')
   OR (p.slug = 'squat'         AND s.slug = 'leg-press')
   OR (p.slug = 'squat'         AND s.slug = 'goblet-squat')
   OR (p.slug = 'deadlift'      AND s.slug = 'romanian-deadlift')
   OR (p.slug = 'deadlift'      AND s.slug = 'trap-bar-deadlift')
   OR (p.slug = 'pull-up'       AND s.slug = 'lat-pulldown')
   OR (p.slug = 'pull-up'       AND s.slug = 'assisted-pull-up')
   OR (p.slug = 'barbell-row'   AND s.slug = 'dumbbell-row')
   OR (p.slug = 'barbell-row'   AND s.slug = 'seated-cable-row')
   OR (p.slug = 'overhead-press' AND s.slug = 'dumbbell-shoulder-press')
   OR (p.slug = 'overhead-press' AND s.slug = 'seated-barbell-press')
   OR (p.slug = 'romanian-deadlift' AND s.slug = 'dumbbell-romanian-deadlift')
   OR (p.slug = 'incline-bench-press' AND s.slug = 'incline-dumbbell-press')
   OR (p.slug = 'cable-fly'     AND s.slug = 'dumbbell-fly')
   OR (p.slug = 'tricep-pushdown' AND s.slug = 'overhead-tricep-extension')
   OR (p.slug = 'leg-press'     AND s.slug = 'hack-squat')
   OR (p.slug = 'leg-curl'      AND s.slug = 'nordic-curl')
   OR (p.slug = 'calf-raise'    AND s.slug = 'seated-calf-raise')
   OR (p.slug = 'face-pull'     AND s.slug = 'band-pull-apart')
   OR (p.slug = 'dumbbell-curl' AND s.slug = 'barbell-curl')
   OR (p.slug = 'lateral-raise' AND s.slug = 'cable-lateral-raise')
   OR (p.slug = 'hip-thrust'    AND s.slug = 'glute-bridge')
   OR (p.slug = 'walking-lunge' AND s.slug = 'reverse-lunge')
   OR (p.slug = 'front-squat'   AND s.slug = 'squat');

-- ════════════════════════════════════════════════════════════════════════════
-- 5. INJURY EXERCISE RESTRICTIONS
-- ════════════════════════════════════════════════════════════════════════════

INSERT IGNORE INTO injury_exercise_restrictions (injury_type, exercise_id, restriction_level, notes)
SELECT 'SHOULDER_IMPINGEMENT', e.id, 'AVOID', 'Overhead movement aggravates impingement'
FROM exercises e WHERE e.slug IN ('overhead-press','seated-barbell-press','dumbbell-shoulder-press','push-press')
UNION ALL
SELECT 'SHOULDER_IMPINGEMENT', e.id, 'MODIFY', 'Use neutral grip; reduce ROM if pain occurs'
FROM exercises e WHERE e.slug IN ('bench-press','incline-bench-press','cable-fly','dumbbell-fly','pull-up','lat-pulldown')
UNION ALL
SELECT 'KNEE_PAIN', e.id, 'AVOID', 'High compressive knee load'
FROM exercises e WHERE e.slug IN ('squat','front-squat','hack-squat','leg-press','walking-lunge','reverse-lunge','goblet-squat')
UNION ALL
SELECT 'KNEE_PAIN', e.id, 'MODIFY', 'Limit ROM; avoid full flexion'
FROM exercises e WHERE e.slug IN ('leg-extension','leg-curl','step-up')
UNION ALL
SELECT 'LOWER_BACK_PAIN', e.id, 'AVOID', 'Axial loading on compromised lumbar spine'
FROM exercises e WHERE e.slug IN ('deadlift','squat','barbell-row','good-morning','stiff-leg-deadlift')
UNION ALL
SELECT 'LOWER_BACK_PAIN', e.id, 'MODIFY', 'Brace core; use belt; reduce load'
FROM exercises e WHERE e.slug IN ('romanian-deadlift','dumbbell-row','seated-cable-row','lat-pulldown','leg-press')
UNION ALL
SELECT 'WRIST_PAIN', e.id, 'AVOID', 'Wrist extension under load'
FROM exercises e WHERE e.slug IN ('bench-press','overhead-press','front-squat','push-up','barbell-curl')
UNION ALL
SELECT 'WRIST_PAIN', e.id, 'MODIFY', 'Use EZ-bar or dumbbells to reduce wrist strain'
FROM exercises e WHERE e.slug IN ('incline-bench-press','dumbbell-bench-press','tricep-pushdown','dumbbell-curl')
UNION ALL
SELECT 'ELBOW_TENDINITIS', e.id, 'AVOID', 'Heavy elbow flexion/extension under load'
FROM exercises e WHERE e.slug IN ('barbell-curl','close-grip-bench-press','skull-crusher','tricep-pushdown')
UNION ALL
SELECT 'ELBOW_TENDINITIS', e.id, 'MODIFY', 'Reduce load; use neutral grip'
FROM exercises e WHERE e.slug IN ('dumbbell-curl','overhead-tricep-extension','lat-pulldown','pull-up')
UNION ALL
SELECT 'HIP_FLEXOR_STRAIN', e.id, 'AVOID', 'Deep hip flexion under load'
FROM exercises e WHERE e.slug IN ('squat','front-squat','deadlift','hip-thrust','walking-lunge')
UNION ALL
SELECT 'HIP_FLEXOR_STRAIN', e.id, 'MODIFY', 'Limit depth; reduce hip flexion range'
FROM exercises e WHERE e.slug IN ('leg-press','romanian-deadlift','glute-bridge','reverse-lunge');

